create or replace function public.create_employee(p_organization_id uuid,p_branch_id uuid,p_first_name text,p_last_name text,p_email text,p_phone text,p_tax_id text,p_pension_id text,p_hire_date date,p_department text,p_position_title text,p_employment_type text,p_bank_name text,p_bank_account_masked text,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare v_id uuid; v_no text; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','manager']::public.app_role[]) then raise exception 'Insufficient HR permission'; end if; if nullif(trim(p_first_name),'') is null or nullif(trim(p_last_name),'') is null then raise exception 'Employee name is required'; end if; if p_employment_type not in ('permanent','contract','temporary','intern') then raise exception 'Invalid employment type'; end if; v_no:=public.next_document_number(p_organization_id,'EMP'); insert into public.employees(organization_id,branch_id,employee_number,first_name,last_name,email,phone,tax_id,pension_id,hire_date,department,position_title,employment_type,bank_name,bank_account_masked,created_by) values(p_organization_id,p_branch_id,v_no,trim(p_first_name),trim(p_last_name),nullif(trim(p_email),''),nullif(trim(p_phone),''),nullif(trim(p_tax_id),''),nullif(trim(p_pension_id),''),coalesce(p_hire_date,current_date),nullif(trim(p_department),''),nullif(trim(p_position_title),''),p_employment_type,nullif(trim(p_bank_name),''),nullif(trim(p_bank_account_masked),''),p_actor_id) returning id into v_id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'hr.employee.created','employee',v_id,jsonb_build_object('number',v_no,'name',trim(p_first_name)||' '||trim(p_last_name))); return jsonb_build_object('id',v_id,'number',v_no); end $$;

create or replace function public.record_attendance(p_organization_id uuid,p_employee_id uuid,p_attendance_date date,p_status text,p_check_in time,p_check_out time,p_regular_hours numeric,p_overtime_hours numeric,p_notes text,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare e public.employees%rowtype; v_id uuid; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','manager','staff']::public.app_role[]) then raise exception 'Insufficient attendance permission'; end if; if p_status not in ('present','absent','late','half_day','remote','holiday','leave') then raise exception 'Invalid attendance status'; end if; select * into e from public.employees where id=p_employee_id and organization_id=p_organization_id and status in ('active','on_leave'); if not found then raise exception 'Employee not found'; end if; insert into public.attendance_entries(organization_id,employee_id,attendance_date,status,check_in,check_out,regular_hours,overtime_hours,notes,created_by) values(p_organization_id,e.id,coalesce(p_attendance_date,current_date),p_status,p_check_in,p_check_out,greatest(coalesce(p_regular_hours,0),0),greatest(coalesce(p_overtime_hours,0),0),nullif(trim(p_notes),''),p_actor_id) on conflict(organization_id,employee_id,attendance_date) do update set status=excluded.status,check_in=excluded.check_in,check_out=excluded.check_out,regular_hours=excluded.regular_hours,overtime_hours=excluded.overtime_hours,notes=excluded.notes,updated_at=now() returning id into v_id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'hr.attendance.recorded','attendance_entry',v_id,jsonb_build_object('employee',e.employee_number,'date',coalesce(p_attendance_date,current_date),'status',p_status)); return jsonb_build_object('id',v_id,'number',e.employee_number||'-'||coalesce(p_attendance_date,current_date)::text); end $$;

create or replace function public.create_leave_request(p_organization_id uuid,p_employee_id uuid,p_leave_type text,p_start_date date,p_end_date date,p_days numeric,p_reason text,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare e public.employees%rowtype; v_id uuid; v_no text; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','manager','staff']::public.app_role[]) then raise exception 'Insufficient leave permission'; end if; if p_leave_type not in ('annual','sick','maternity','paternity','unpaid','other') or p_end_date<p_start_date or p_days<=0 then raise exception 'Invalid leave request'; end if; select * into e from public.employees where id=p_employee_id and organization_id=p_organization_id and status in ('active','on_leave'); if not found then raise exception 'Employee not found'; end if; v_no:=public.next_document_number(p_organization_id,'LEV'); insert into public.leave_requests(organization_id,employee_id,leave_number,leave_type,start_date,end_date,days,status,reason,created_by) values(p_organization_id,e.id,v_no,p_leave_type,p_start_date,p_end_date,p_days,'submitted',nullif(trim(p_reason),''),p_actor_id) returning id into v_id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'hr.leave.submitted','leave_request',v_id,jsonb_build_object('number',v_no,'employee',e.employee_number,'days',p_days)); return jsonb_build_object('id',v_id,'number',v_no); end $$;

create or replace function public.set_leave_request_status(p_organization_id uuid,p_leave_request_id uuid,p_status text,p_approver_note text,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare l public.leave_requests%rowtype; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','manager']::public.app_role[]) then raise exception 'Insufficient leave approval permission'; end if; if p_status not in ('approved','rejected','cancelled') then raise exception 'Invalid leave status'; end if; select * into l from public.leave_requests where id=p_leave_request_id and organization_id=p_organization_id for update; if not found or l.status not in ('submitted','approved') then raise exception 'Leave request not available'; end if; update public.leave_requests set status=p_status,approver_note=nullif(trim(p_approver_note),''),approved_by=case when p_status='approved' then p_actor_id else approved_by end,approved_at=case when p_status='approved' then now() else approved_at end,updated_at=now() where id=l.id; if p_status='approved' and current_date between l.start_date and l.end_date then update public.employees set status='on_leave',updated_at=now() where id=l.employee_id; end if; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'hr.leave.'||p_status,'leave_request',l.id,jsonb_build_object('number',l.leave_number)); return jsonb_build_object('id',l.id,'number',l.leave_number,'status',p_status); end $$;

create or replace function public.set_salary_structure(p_organization_id uuid,p_employee_id uuid,p_effective_from date,p_base_salary numeric,p_recurring_allowances numeric,p_recurring_deductions numeric,p_employee_pension_rate numeric,p_employer_pension_rate numeric,p_income_tax_rate numeric,p_overtime_hourly_rate numeric,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare e public.employees%rowtype; v_id uuid; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','accountant']::public.app_role[]) then raise exception 'Insufficient payroll permission'; end if; select * into e from public.employees where id=p_employee_id and organization_id=p_organization_id and status<>'terminated'; if not found then raise exception 'Employee not found'; end if; if p_base_salary<0 or p_recurring_allowances<0 or p_recurring_deductions<0 or p_employee_pension_rate not between 0 and 100 or p_employer_pension_rate not between 0 and 100 or p_income_tax_rate not between 0 and 100 or p_overtime_hourly_rate<0 then raise exception 'Invalid salary structure'; end if; update public.salary_structures set is_active=false where employee_id=e.id and organization_id=p_organization_id and is_active; insert into public.salary_structures(organization_id,employee_id,effective_from,base_salary,recurring_allowances,recurring_deductions,employee_pension_rate,employer_pension_rate,income_tax_rate,overtime_hourly_rate,is_active,created_by) values(p_organization_id,e.id,coalesce(p_effective_from,current_date),p_base_salary,p_recurring_allowances,p_recurring_deductions,p_employee_pension_rate,p_employer_pension_rate,p_income_tax_rate,p_overtime_hourly_rate,true,p_actor_id) returning id into v_id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'hr.salary.updated','salary_structure',v_id,jsonb_build_object('employee',e.employee_number,'base_salary',p_base_salary)); return jsonb_build_object('id',v_id,'number',e.employee_number,'amount',p_base_salary); end $$;

revoke all on function public.create_employee(uuid,uuid,text,text,text,text,text,text,date,text,text,text,text,text,uuid) from public; grant execute on function public.create_employee(uuid,uuid,text,text,text,text,text,text,date,text,text,text,text,text,uuid) to authenticated;
revoke all on function public.record_attendance(uuid,uuid,date,text,time,time,numeric,numeric,text,uuid) from public; grant execute on function public.record_attendance(uuid,uuid,date,text,time,time,numeric,numeric,text,uuid) to authenticated;
revoke all on function public.create_leave_request(uuid,uuid,text,date,date,numeric,text,uuid) from public; grant execute on function public.create_leave_request(uuid,uuid,text,date,date,numeric,text,uuid) to authenticated;
revoke all on function public.set_leave_request_status(uuid,uuid,text,text,uuid) from public; grant execute on function public.set_leave_request_status(uuid,uuid,text,text,uuid) to authenticated;
revoke all on function public.set_salary_structure(uuid,uuid,date,numeric,numeric,numeric,numeric,numeric,numeric,numeric,uuid) from public; grant execute on function public.set_salary_structure(uuid,uuid,date,numeric,numeric,numeric,numeric,numeric,numeric,numeric,uuid) to authenticated;